mapper.select:
SELECT * FROM ( SELECT r.REPORT_ID AS REPORTID, r.TARGET_TYPE AS TARGETTYPE, r.TARGET_ID AS TARGETID, r.FK_MEMBERID AS MEMBERID, r.FK_REASON_ID AS REASONID, rr.REASON_NAME AS REASONNAME, r.REPORT_CONTENT AS REPORTCONTENT, r.PROCESS_STATUS AS STATUS, r.CREATED_AT AS CREATEDAT, r.PROCESS_REASON AS PROCESSREASON, r.PROCESS_AT AS PROCESSAT, (SELECT COUNT(*) FROM TBL_REPORT r2 LEFT JOIN TBL_JOB_POSTING j2 ON r2.TARGET_TYPE = 1 AND r2.TARGET_ID = j2.JOB_ID LEFT JOIN TBL_POST p2 ON r2.TARGET_TYPE = 2 AND r2.TARGET_ID = p2.POST_ID LEFT JOIN TBL_COMMENT c2 ON r2.TARGET_TYPE = 3 AND r2.TARGET_ID = c2.COMMENT_ID WHERE CASE r2.TARGET_TYPE WHEN 1 THEN j2.FK_MEMBERID WHEN 2 THEN p2.FK_MEMBERID WHEN 3 THEN c2.FK_MEMBERID END = CASE r.TARGET_TYPE WHEN 1 THEN j.FK_MEMBERID WHEN 2 THEN p.FK_MEMBERID WHEN 3 THEN c.FK_MEMBERID END ) AS REPORTCOUNT, CASE r.TARGET_TYPE WHEN 1 THEN j.TITLE WHEN 2 THEN p.TITLE WHEN 3 THEN c.CONTENT END AS TARGETTITLE, CASE r.TARGET_TYPE WHEN 1 THEN j.FK_MEMBERID WHEN 2 THEN p.FK_MEMBERID WHEN 3 THEN c.FK_MEMBERID END AS REPORTEDMEMBERID, ROW_NUMBER() OVER (ORDER BY r.CREATED_AT DESC) AS rn FROM TBL_REPORT r LEFT JOIN TBL_REPORT_REASON rr ON r.FK_REASON_ID = rr.REASON_ID LEFT JOIN TBL_JOB_POSTING j ON r.TARGET_TYPE = 1 AND r.TARGET_ID = j.JOB_ID LEFT JOIN TBL_POST p ON r.TARGET_TYPE = 2 AND r.TARGET_ID = p.POST_ID LEFT JOIN TBL_COMMENT c ON r.TARGET_TYPE = 3 AND r.TARGET_ID = c.COMMENT_ID
AND NOT (r.TARGET_TYPE = 1 AND j.STATUS = '임시저장')
AND r.FK_MEMBERID LIKE '%' || #{search} || '%'
AND r.TARGET_TYPE = #{type}
AND rr.REASON_NAME = #{reason}
AND r.PROCESS_STATUS = #{status}
) WHERE rn BETWEEN #{offset}+1 AND #{offset}+#{limit}

        SELECT COUNT(*)
        FROM TBL_REPORT r
		LEFT JOIN TBL_REPORT_REASON rr ON r.FK_REASON_ID = rr.REASON_ID
		LEFT JOIN TBL_JOB_POSTING j    ON r.TARGET_TYPE = 1 AND r.TARGET_ID = j.JOB_ID

        	AND NOT (r.TARGET_TYPE = 1 AND j.STATUS = '임시저장')

                AND r.FK_MEMBERID LIKE '%' || #{search} || '%'


                AND r.TARGET_TYPE = #{type}


                AND rr.REASON_NAME = #{reason}


                AND r.PROCESS_STATUS = #{status}

mapper.update:
UPDATE TBL_JOB_POSTING
SET IS_HIDDEN = 1
WHERE JOB_ID = #{jobId}

UPDATE TBL_POST
SET IS_HIDDEN = 1
WHERE POST_ID = #{postId}

UPDATE TBL_COMMENT
SET IS_HIDDEN = 1
WHERE COMMENT_ID = #{commentId}
